import { expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

describe("@reads", () => {
  // T014_01: @reads([TaskRow]) inside @component Agent, TaskRow inside @component Store in @dependsOn — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T014.T014_01
  it("T014_01: @reads store model in @dependsOn — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      namespace Components {
        @component(#{
          type: ComponentType.Store,
        })
        namespace TaskStore {
          model TaskRow { id: string; }
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.TaskStore])
        namespace ReviewAgent {
          @tool(#{ sequential: false })
          @reads([Components.TaskStore.TaskRow])
          op get_task(): void;
        }
      }
    `);
  });

  // T014_02: @reads on model — TypeSpec extern dec rejects model target
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T014.T014_02
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_reads:Products.A10nBlueprintEngine.Features.OperationCallGraph.reads_op_only:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_writes:Products.A10nBlueprintEngine.Features.OperationCallGraph.reads_op_only:must
  it("T014_02: @reads on model — TypeSpec extern dec rejects non-operation target", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      namespace Components {
        @component(#{
          type: ComponentType.Store,
        })
        namespace TaskStore {
          model TaskRow { id: string; }
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.TaskStore])
        namespace ReviewAgent {
          @reads([Components.TaskStore.TaskRow])
          model QueryResult { id: string; }
        }
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "decorator-wrong-target",
    });
  });

  // T014_03: @reads([PayloadModel]) where PayloadModel is inside non-Store component — reads-invalid-target
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T014.T014_03
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_reads:Products.A10nBlueprintEngine.Features.OperationCallGraph.reads_target_store:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_writes:Products.A10nBlueprintEngine.Features.OperationCallGraph.reads_target_store:must
  it("T014_03: @reads model inside non-Store component — reads-invalid-target", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      namespace Components {
        @component(#{
          type: ComponentType.Service,
        })
        namespace MyApiService {
          model PayloadModel { data: string; }
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.MyApiService])
        namespace ReviewAgent {
          @tool(#{ sequential: false })
          @reads([Components.MyApiService.PayloadModel])
          op get_task(): void;
        }
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/reads-invalid-target",
      message: /PayloadModel/,
    });
  });

  // T014_04: @reads(["TaskRow"]) string literal — TypeSpec type checker rejects string literal against Model[]
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T014.T014_04
  it("T014_04: @reads with string literal — TypeSpec rejects invalid-argument", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{
        type: ComponentType.Agent,
      })
      namespace Components.MyAgent {
        @tool(#{ sequential: false })
        @reads(["TaskRow"])
        op get_task(): void;
      }
    `);
    expectDiagnostics(diagnostics, [
      { code: "invalid-argument" },
    ]);
  });

  // T014_06: @tool(#{ sequential: false }) op with no @reads — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T014.T014_06
  it("T014_06: @tool(#{ sequential: false }) op with no @reads — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{
        type: ComponentType.Agent,
      })
      namespace Components.ReviewAgent {
        @tool(#{ sequential: false })
        op get_task(): void;
      }
    `);
  });

  // T014_10: @reads([TaskRow]) with @dependsOn([Components.TaskStore]) — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T014.T014_10
  it("T014_10: @reads with @dependsOn — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      namespace Components {
        @component(#{
          type: ComponentType.Store,
        })
        namespace TaskStore {
          model TaskRow { id: string; status: string; }
        }

        @component(#{
          type: ComponentType.Service,
        })
        @dependsOn([Components.TaskStore])
        namespace TaskService {
          @operation(#{})
          @reads([Components.TaskStore.TaskRow])
          op get_task(): void;
        }
      }
    `);
  });

  // T014_08: @dataset with @reads pointing at @storageObject model — zero reads-invalid-target diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T014.T014_08
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_reads:Products.A10nBlueprintEngine.Features.DatasetAuthoring.reads_storage:should
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_reads
  it("T014_08: @dataset @reads a @storageObject model — zero reads-invalid-target diagnostics", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      namespace Components {
        @component(#{ type: ComponentType.Store })
        @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
        namespace DataFileStore {
          @mediaTypeHint("application/yaml")
          @storageObject(#{ path: "items.yaml" })
          model ItemRegistry {}
        }

        @component(#{ type: ComponentType.Agent })
        @dependsOn([Components.DataFileStore])
        namespace ReviewAgent {
          @dataset(#{ title: "Items" })
          @reads([Components.DataFileStore.ItemRegistry])
          op d001_items(): void;
        }
      }
    `);
    const invalids = diagnostics.filter((d) => d.code === "@a10n/blueprint-typespec/reads-invalid-target");
    if (invalids.length > 0) {
      throw new Error(`Expected no reads-invalid-target diagnostics, got: ${JSON.stringify(invalids.map((d) => d.message))}`);
    }
  });

  // T014_09: @dataset with two @reads storage targets — rejects the extra target
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T014.T014_09
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_reads:Products.A10nBlueprintEngine.Features.DatasetAuthoring.exactly_one_reads:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_writes:Products.A10nBlueprintEngine.Features.DatasetAuthoring.exactly_one_reads:must
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_reads
  it("T014_09: @dataset @reads two @storageObject models — second target rejected", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      namespace Components {
        @component(#{ type: ComponentType.Store })
        @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
        namespace DataFileStore {
          @mediaTypeHint("application/yaml")
          @storageObject(#{ path: "items.yaml" })
          model ItemRegistry {}
          @mediaTypeHint("application/yaml")
          @storageObject(#{ path: "extra.yaml" })
          model ExtraRegistry {}
        }

        @component(#{ type: ComponentType.Agent })
        @dependsOn([Components.DataFileStore])
        namespace ReviewAgent {
          @dataset(#{ title: "Multi-read dataset" })
          @reads([Components.DataFileStore.ItemRegistry, Components.DataFileStore.ExtraRegistry])
          op d001_multi(): void;
        }
      }
    `);
    const invalids = diagnostics.filter((d) => d.code === "@a10n/blueprint-typespec/reads-invalid-target");
    if (invalids.length === 0) {
      throw new Error("Expected reads-invalid-target for second @storageObject target but got none");
    }
  });

  // T014_07: @reads([TaskRow, ProjectRow]) both in Store dependencies — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T014.T014_07
  it("T014_07: @reads multiple store models in @dependsOn — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      namespace Components {
        @component(#{
          type: ComponentType.Store,
        })
        namespace TaskStore {
          model TaskRow { id: string; }
          model ProjectRow { id: string; name: string; }
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.TaskStore])
        namespace ReviewAgent {
          @tool(#{ sequential: false })
          @reads([Components.TaskStore.TaskRow, Components.TaskStore.ProjectRow])
          op get_task(): void;
        }
      }
    `);
  });
});
